let esize : integer{} = 64;
let g : integer = UInt(Pg);
let n : integer = UInt(Zn);
let d : integer = UInt(Zd);
let s_esize : integer{} = 64;
let d_esize : integer{} = 64;
let unsigned : boolean = TRUE;
let rounding : FPRounding = FPRounding_ZERO;
let merging : boolean = FALSE;

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mask : bits(PL) = P{}(g);
let operand : bits(VL) = if AnyActiveElement{PL}(mask, esize) then Z{VL}(n) else Zeros{VL};
var result : bits(VL) = if merging then Z{VL}(d) else Zeros{VL};

for e = 0 to elements-1 do
    if ActivePredicateElement{PL}(mask, e, esize) then
        let element : bits(esize) = operand[e*:esize];
        let res : bits(d_esize) = FPToFixed{d_esize, s_esize}(element[s_esize-1:0], 0, unsigned,
                                                              FPCR(), rounding);
        result[e*:esize] = Extend{esize}(res, unsigned);
    end;
end;

Z{VL}(d) = result;
